import React, { FC, useCallback, useRef, useMemo } from 'react';
import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { Dimensions } from 'react-native';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { ScreenProps } from '../../routes/Models';
import { eventScreenViewV3, eventModalView, eventSelectContent } from '~/constants/functions';
import MyOrdersDetailView from './view';
import { useShallow } from "zustand/react/shallow";
import { useRootStore } from '../../store';
import { OrderDetailStatus, TransactionType } from '../../store/rewardProgram/models';
import { getOrderDetail } from '../../store/rewardProgram/services';
import { formatToCurrency } from '../../utils/functions';
import { moment } from '../../services/moment';
import {
  getTransactionGainType,
  getFormattedPointsValue,
  getFormattedHighlightText,
  getFormattedPointsValueForMarketplace,
  getPaymentTypeLabel,
  getMarketplaceTitle,
  getCleanedImageUrl,
} from './utils';
import { MarketplaceContentData, MarketplaceItemData, STATUS_COLORS } from './Models';

const MyOrdersDetails: FC<ScreenProps<'MyOrdersDetails'>> = ({
  navigation,
  route,
}) => {
  const hasFocused = useRef(false);
  const modalizeRef = useRef<PropsModalizeRef>(null);
  const modalizeRefInfo = useRef<PropsModalizeRef>(null);

  const { orderDetail, orderDetailActions } =
    useRootStore(
      useShallow((state) => ({
        orderDetail: state.orderDetail,
        orderDetailActions: state.orderDetailActions,
      })),
    );

  const transactionId = route.params?.transactionId;
  const passedType = route.params?.type;
  const passedIcon = route.params?.icon;
  const passedStatus = route.params?.status;
  const passedOrigination = route.params?.origination;

  useFocusEffect(
    useCallback(() => {
      if (!hasFocused.current) {
        eventScreenViewV3(  
          'detalhe_pedido',
          'hub_recompensas_spmais',
          'monetizacao',
          {
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'detalhe_pedido',
          });
        hasFocused.current = true;
      }

      if (transactionId) {
        orderDetailActions.reset();
        getOrderDetail({ transactionId });
      }

      return () => {
        hasFocused.current = false;
        orderDetailActions.reset();
      };
    }, [transactionId, orderDetailActions])
  );

  const handleGoBack = () => {
    navigation.goBack();
  };

  const handleOpenReportProblem = () => {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'relatar_problema',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'detalhe_pedido',
    });

    eventModalView({
      content_id: 'contato_telefones',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'detalhe_pedido',
    });

    modalizeRef.current?.open?.();
  };

  const handleCloseReportProblem = () => {
    modalizeRef.current?.close?.();
  };

  const handleOpenInfo = () => {
    modalizeRefInfo.current?.open?.();
  };

  const handleCloseInfo = () => {
    modalizeRefInfo.current?.close?.();
  };

  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
  const { height } = Dimensions.get('window');

  const handleRetry = () => {
    if (transactionId) {
      getOrderDetail({ transactionId });
    }
  };

  const transaction = orderDetail.orderDetail;

  const isValidTransactionType = (type: string | undefined): type is TransactionType => {
    return type === 'CREDIT' || type === 'RESCUE' || type === 'EXPIRED' || type === 'REFUNDED';
  };

  const enrichedTransaction = transaction ? {
    ...transaction,
    type: isValidTransactionType(passedType) ? passedType : transaction.type,
    icon: passedIcon || transaction.icon,
    status: passedStatus || transaction.status,
    details: {
      ...transaction.details,
      provider: passedOrigination || transaction.details?.provider || '',
    },
  } : undefined;

  const isCashback = passedType === 'RESCUE';

  const processedData = useMemo(() => {
    if (!enrichedTransaction) {
      return {
        cardTitle: '',
        formattedPointsValue: '',
        highlightText: '',
        formattedCurrencyValue: '',
        marketplaceContent: undefined,
        showOrderNumber: false,
        showStatus: false,
        showValue: false,
      };
    }

    const gainType = getTransactionGainType(enrichedTransaction);
    const formattedCurrencyValue = formatToCurrency(enrichedTransaction.currencyValue);
    const marketplaceValuePoints = enrichedTransaction?.marketplace?.valuePoints;
    const formattedPointsValue = marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
      ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
      : getFormattedPointsValue(enrichedTransaction.amount, enrichedTransaction.type);
    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
    const highlightText = getFormattedHighlightText(enrichedTransaction.date, gainType, moment);

    const isMarketplace = !!enrichedTransaction?.marketplace;
    const marketplace = enrichedTransaction?.marketplace;

    let marketplaceContent: MarketplaceContentData | undefined;
    if (isMarketplace && marketplace) {
      const firstOrder = marketplace.orders?.[0];
      const firstPayment = marketplace.payments?.[0];
      const vendorName = firstOrder?.vendor || '';

      const items: MarketplaceItemData[] = [];
      marketplace.orders?.forEach(order => {
        order.items?.forEach(item => {
          items.push({
            name: item.name,
            quantity: item.quantity,
            valuePoints: getFormattedPointsValueForMarketplace(item.valuePoints),
            imageUrl: item.imageUrl,
            cleanedImageUrl: getCleanedImageUrl(item.imageUrl),
          });
        });
      });

      marketplaceContent = {
        orderNumber: enrichedTransaction.id,
        status: enrichedTransaction.status,
        statusColor: enrichedTransaction.status ? (STATUS_COLORS[enrichedTransaction.status] || 'neutral') : undefined,
        paymentType: firstPayment ? getPaymentTypeLabel(firstPayment.paymentType) : undefined,
        shippingValuePoints: marketplace.shippingValuePoints !== undefined && marketplace.shippingValuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.shippingValuePoints)
          : undefined,
        valuePoints: marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
          : undefined,
        vendorName: vendorName || undefined,
        items,
      };
    }

    return {
      cardTitle,
      formattedPointsValue,
      highlightText,
      formattedCurrencyValue,
      marketplaceContent,
      showOrderNumber: !isMarketplace,
      showStatus: !isMarketplace,
      showValue: !isMarketplace,
    };
  }, [enrichedTransaction]);

  return (
    <MyOrdersDetailView
      handleGoBack={handleGoBack}
      transaction={enrichedTransaction}
      modalizeRef={modalizeRef}
      modalizeRefInfo={modalizeRefInfo}
      handleOpenReportProblem={handleOpenReportProblem}
      handleCloseReportProblem={handleCloseReportProblem}
      handleOpenInfo={handleOpenInfo}
      handleCloseInfo={handleCloseInfo}
      isLoading={isLoading}
      hasError={hasError}
      handleRetry={handleRetry}
      isCashback={isCashback}
      cardTitle={processedData.cardTitle}
      formattedPointsValue={processedData.formattedPointsValue}
      highlightText={processedData.highlightText}
      formattedCurrencyValue={processedData.formattedCurrencyValue}
      marketplaceContent={processedData.marketplaceContent}
      showOrderNumber={processedData.showOrderNumber}
      showStatus={processedData.showStatus}
      showValue={processedData.showValue}
      height={height}
    />
  );
};

export default MyOrdersDetails;

